9	// NewHelpCmd creates a custom help command that supports a hidden -t flag
10	// to display the entire command tree.
11	func NewHelpCmd(rootCmd *cobra.Command) *cobra.Command {
12		var showTree bool
13	
14		helpCmd := &cobra.Command{
15			Use:   "help [command]",
16			Short: "Help about any command",
17			Long: `Provides help for any Entire CLI subcommand.
18	Simply type '` + rootCmd.Name() + ` help [command]' for full details.`,
19			Run: func(_ *cobra.Command, args []string) {
20				if showTree {
21					printCommandTree(rootCmd)
22					return
23				}
24	
25				// Default help behavior
26				targetCmd, _, err := rootCmd.Find(args)
27				if err != nil || targetCmd == nil {
28					targetCmd = rootCmd
29				}
30				targetCmd.Help() //nolint:errcheck,gosec // Help() only fails on write errors to stdout
31			},
32		}
33	
34		helpCmd.Flags().BoolVarP(&showTree, "tree", "t", false, "Show full command tree")
35		helpCmd.Flags().MarkHidden("tree") //nolint:errcheck,gosec // flag is defined above
36	
37		return helpCmd
38	}
39	
40	func printCommandTree(cmd *cobra.Command) {
41		fmt.Println(cmd.Name())
42		printChildren(cmd, "")
43	}
44	
45	func printChildren(cmd *cobra.Command, indent string) {
46		visibleCmds := getVisibleCommands(cmd)
47	
48		for i, sub := range visibleCmds {
49			isLast := i == len(visibleCmds)-1
50			printNode(sub, indent, isLast)
51		}
52	}
53	
54	func printNode(cmd *cobra.Command, indent string, isLast bool) {
55		var branch, childIndent string
56		if isLast {
57			branch = "└── "
58			childIndent = indent + "    "
59		} else {
60			branch = "├── "
61			childIndent = indent + "│   "
62		}
63	
64		fmt.Printf("%s%s%s", indent, branch, cmd.Name())
65		if cmd.Short != "" {
66			fmt.Printf(" - %s", cmd.Short)
67		}
68		fmt.Println()
69	
70		printChildren(cmd, childIndent)
71	}
72	
73	func getVisibleCommands(cmd *cobra.Command) []*cobra.Command {
74		var visible []*cobra.Command
75		for _, sub := range cmd.Commands() {
76			if !sub.Hidden && sub.Name() != "help" {
77				visible = append(visible, sub)
78			}
79		}
80		return visible
81	}
