19	func main() {
20		if err := run(context.Background(), os.Args[1:]); err != nil {
21			fmt.Fprintf(os.Stderr, "error: %v\n", err)
22			os.Exit(1)
23		}
24	}
25	
26	func run(ctx context.Context, args []string) error {
27		if len(args) == 0 {
28			return usageError("")
29		}
30	
31		switch args[0] {
32		case "sync":
33			return runSyncLike(ctx, "sync", args[1:], false, gitsync.ModeSync)
34		case "replicate":
35			return runSyncLike(ctx, "replicate", args[1:], false, gitsync.ModeReplicate)
36		case "plan":
37			return runSyncLike(ctx, "plan", args[1:], true, "")
38		case "bootstrap":
39			return runBootstrap(ctx, args[1:])
40		case "probe":
41			return runProbe(ctx, args[1:])
42		case "fetch":
43			return runFetch(ctx, args[1:])
44		case "version", "--version":
45			fmt.Printf("git-sync %s (commit %s, built %s)\n",
46				versioninfo.Version, versioninfo.Commit, versioninfo.Date)
47			return nil
48		case "help", "-h", "--help":
49			return usageError("")
50		default:
51			return usageError(fmt.Sprintf("unknown command %q", args[0]))
52		}
53	}
