55	func runSyncLike(ctx context.Context, name string, args []string, dryRun bool, defaultMode gitsync.OperationMode) error {
56		fs := flag.NewFlagSet(name, flag.ContinueOnError)
57		fs.SetOutput(os.Stderr)
58	
59		var mappings multiStringFlag
60		var jsonOutput bool
61		var sourceAuth gitsync.EndpointAuth
62		var targetAuth gitsync.EndpointAuth
63		req := unstable.SyncRequest{DryRun: dryRun}
64	
65		fs.StringVar(&req.Source.URL, "source-url", "", "source repository URL")
66		fs.StringVar(&req.Target.URL, "target-url", "", "target repository URL")
67		fs.BoolVar(&req.Source.FollowInfoRefsRedirect, "source-follow-info-refs-redirect", envBool("GITSYNC_SOURCE_FOLLOW_INFO_REFS_REDIRECT"), "send follow-up source RPCs to the final /info/refs redirect host")
68		fs.BoolVar(&req.Target.FollowInfoRefsRedirect, "target-follow-info-refs-redirect", envBool("GITSYNC_TARGET_FOLLOW_INFO_REFS_REDIRECT"), "send follow-up target RPCs to the final /info/refs redirect host")
69	
70		fs.StringVar(&sourceAuth.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
71		fs.StringVar(&targetAuth.Token, "target-token", envOr("GITSYNC_TARGET_TOKEN", ""), "target token/password")
72		fs.StringVar(&sourceAuth.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
73		fs.StringVar(&targetAuth.Username, "target-username", envOr("GITSYNC_TARGET_USERNAME", "git"), "target basic auth username")
74		fs.BoolVar(&sourceAuth.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
75		fs.BoolVar(&targetAuth.SkipTLSVerify, "target-insecure-skip-tls-verify", envBool("GITSYNC_TARGET_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the target")
76	
77		fs.StringVar(&sourceAuth.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
78		fs.StringVar(&targetAuth.BearerToken, "target-bearer-token", envOr("GITSYNC_TARGET_BEARER_TOKEN", ""), "target bearer token")
79	
80		branches := fs.String("branch", "", "comma-separated branch list; default is all source branches")
81		fs.Var(&mappings, "map", "ref mapping in src:dst form; short names map branches, full refs map exact refs")
82		modeValue := operationModeFlag(defaultOperationMode(defaultMode))
83		if name == "plan" {
84			fs.Var(&modeValue, "mode", "operation mode: sync or replicate")
85		}
86		fs.BoolVar(&req.Policy.IncludeTags, "tags", false, "mirror tags")
87		fs.BoolVar(&req.Policy.Force, "force", false, "allow non-fast-forward branch updates and retarget tags")
88		fs.BoolVar(&req.Policy.Prune, "prune", false, "delete managed target refs that no longer exist on source")
89		fs.BoolVar(&req.Options.CollectStats, "stats", false, "print transfer statistics")
90		fs.BoolVar(&req.Options.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
91		fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
92		fs.IntVar(&req.Options.MaterializedMaxObjects, "materialized-max-objects", unstable.DefaultMaterializedMaxObjects, "abort non-relay materialized syncs above this many objects")
93		fs.Int64Var(&req.Options.MaxPackBytes, "max-pack-bytes", 0, "abort bootstrap-relay push if the streamed source pack exceeds this many bytes")
94		fs.Int64Var(&req.Options.TargetMaxPackBytes, "target-max-pack-bytes", 0, "target receive-pack body size limit; batches are planned and auto-subdivided to fit")
95		protocolValue := protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
96		fs.Var(&protocolValue, "protocol", "protocol mode: auto, v1, or v2")
97		fs.BoolVar(&req.Options.Verbose, "v", false, "verbose logging")
98	
99		if err := fs.Parse(args); err != nil {
100			return fmt.Errorf("parse flags: %w", err)
101		}
102		req.Policy.Mode = gitsync.OperationMode(modeValue)
103		req.Policy.Protocol = gitsync.ProtocolMode(protocolValue)
104	
105		positional := fs.Args()
106		if req.Source.URL == "" && len(positional) > 0 {
107			req.Source.URL = positional[0]
108		}
109		if req.Target.URL == "" && len(positional) > 1 {
110			req.Target.URL = positional[1]
111		}
112		if len(positional) > 2 {
113			return usageError("too many positional arguments")
114		}
115	
116		if *branches != "" {
117			req.Scope.Branches = splitCSV(*branches)
118		}
119		for _, raw := range mappings {
120			mapping, err := validation.ParseMapping(raw)
121			if err != nil {
122				return fmt.Errorf("parse mapping %q: %w", raw, err)
123			}
124			req.Scope.Mappings = append(req.Scope.Mappings, gitsync.RefMapping{
125				Source: mapping.Source,
126				Target: mapping.Target,
127			})
128		}
129	
130		if req.Source.URL == "" || req.Target.URL == "" {
131			return usageError(name + " requires source and target repository URLs")
132		}
133	
134		client := unstable.New(unstable.Options{
135			Auth: gitsync.StaticAuthProvider{Source: sourceAuth, Target: targetAuth},
136		})
137		var (
138			result unstable.Result
139			err    error
140		)
141		if dryRun {
142			result, err = client.Plan(ctx, req)
143		} else {
144			if req.Policy.Mode == gitsync.ModeReplicate {
145				result, err = client.Replicate(ctx, req)
146			} else {
147				result, err = client.Sync(ctx, req)
148			}
149		}
150		if err != nil {
151			return fmt.Errorf("sync: %w", err)
152		}
153		printOutput(jsonOutput, result)
154	
155		if !dryRun && result.Blocked > 0 {
156			return errors.New("one or more branches were skipped because the target was not fast-forwardable")
157		}
158		return nil
159	}
