305	func runFetch(ctx context.Context, args []string) error {
306		fs := flag.NewFlagSet("fetch", flag.ContinueOnError)
307		fs.SetOutput(os.Stderr)
308	
309		var haveRefs multiStringFlag
310		var haveHashesRaw multiStringFlag
311		var jsonOutput bool
312		var sourceAuth gitsync.EndpointAuth
313		req := unstable.FetchRequest{}
314	
315		fs.StringVar(&req.Source.URL, "source-url", "", "source repository URL")
316		fs.BoolVar(&req.Source.FollowInfoRefsRedirect, "source-follow-info-refs-redirect", envBool("GITSYNC_SOURCE_FOLLOW_INFO_REFS_REDIRECT"), "send follow-up source RPCs to the final /info/refs redirect host")
317		fs.StringVar(&sourceAuth.Token, "source-token", envOr("GITSYNC_SOURCE_TOKEN", ""), "source token/password")
318		fs.StringVar(&sourceAuth.Username, "source-username", envOr("GITSYNC_SOURCE_USERNAME", "git"), "source basic auth username")
319		fs.StringVar(&sourceAuth.BearerToken, "source-bearer-token", envOr("GITSYNC_SOURCE_BEARER_TOKEN", ""), "source bearer token")
320		fs.BoolVar(&sourceAuth.SkipTLSVerify, "source-insecure-skip-tls-verify", envBool("GITSYNC_SOURCE_INSECURE_SKIP_TLS_VERIFY"), "skip TLS certificate verification for the source")
321		branches := fs.String("branch", "", "comma-separated branch list; default is all source branches")
322		fs.BoolVar(&req.IncludeTags, "tags", false, "include tags in the fetch request")
323		fetchProtocol := protocolModeFlag(protocolMode(envOr("GITSYNC_PROTOCOL", validation.ProtocolAuto)))
324		fs.Var(&fetchProtocol, "protocol", "protocol mode: auto, v1, or v2")
325		fs.BoolVar(&req.Options.CollectStats, "stats", false, "print transfer statistics")
326		fs.BoolVar(&req.Options.MeasureMemory, "measure-memory", false, "sample elapsed time and Go heap usage")
327		fs.BoolVar(&jsonOutput, "json", false, "print JSON output")
328		fs.Var(&haveRefs, "have-ref", "source ref name to advertise as have; short names map to branches")
329		fs.Var(&haveHashesRaw, "have", "explicit object hash to advertise as have")
330	
331		if err := fs.Parse(args); err != nil {
332			return fmt.Errorf("parse flags: %w", err)
333		}
334		req.Protocol = gitsync.ProtocolMode(fetchProtocol)
335	
336		positional := fs.Args()
337		if req.Source.URL == "" && len(positional) > 0 {
338			req.Source.URL = positional[0]
339		}
340		if len(positional) > 1 {
341			return usageError("too many positional arguments")
342		}
343		if req.Source.URL == "" {
344			return usageError("fetch requires a source repository URL")
345		}
346		if *branches != "" {
347			req.Scope.Branches = splitCSV(*branches)
348		}
349	
350		haveHashes := make([]plumbing.Hash, 0, len(haveHashesRaw))
351		for _, raw := range haveHashesRaw {
352			hash := plumbing.NewHash(strings.TrimSpace(raw))
353			if hash.IsZero() {
354				return fmt.Errorf("invalid --have %q", raw)
355			}
356			haveHashes = append(haveHashes, hash)
357		}
358	
359		req.HaveRefs = append(req.HaveRefs, haveRefs...)
360		req.HaveHashes = append(req.HaveHashes, haveHashes...)
361		result, err := unstable.New(unstable.Options{
362			Auth: gitsync.StaticAuthProvider{Source: sourceAuth},
363		}).Fetch(ctx, req)
364		if err != nil {
365			return fmt.Errorf("fetch: %w", err)
366		}
367		printOutput(jsonOutput, result)
368		return nil
369	}
