371	func printOutput(jsonOutput bool, value interface{ Lines() []string }) {
372		if jsonOutput {
373			data, err := marshalOutput(value)
374			if err != nil {
375				fmt.Fprintf(os.Stderr, "error: encode JSON output: %v\n", err)
376				os.Exit(1)
377			}
378			fmt.Println(string(data))
379			return
380		}
381	
382		for _, line := range value.Lines() {
383			fmt.Println(line)
384		}
385	}
386	
387	func marshalOutput(value interface{}) ([]byte, error) {
388		data, err := json.MarshalIndent(value, "", "  ")
389		if err != nil {
390			return nil, fmt.Errorf("marshal JSON: %w", err)
391		}
392		return data, nil
393	}
