574	type protocolMode gitsync.ProtocolMode
575	type operationMode gitsync.OperationMode
576	
577	type protocolModeFlag protocolMode
578	type operationModeFlag operationMode
579	
580	func (p *protocolModeFlag) String() string {
581		return string(*p)
582	}
583	
584	func (p *protocolModeFlag) Set(value string) error {
585		mode, err := validation.NormalizeProtocolMode(value)
586		if err != nil {
587			return fmt.Errorf("normalize protocol: %w", err)
588		}
589		*p = protocolModeFlag(protocolMode(gitsync.ProtocolMode(mode)))
590		return nil
591	}
592	
593	func (m *operationModeFlag) String() string {
594		return string(*m)
595	}
596	
597	func (m *operationModeFlag) Set(value string) error {
598		switch gitsync.OperationMode(value) {
599		case gitsync.ModeSync, gitsync.ModeReplicate:
600			*m = operationModeFlag(operationMode(value))
601			return nil
602		default:
603			return fmt.Errorf("unsupported mode %q", value)
604		}
605	}
606	
607	// defaultOperationMode returns the starting value for the --mode flag.
608	// Subcommands that pin a mode (sync, replicate) pass it in; plan passes ""
609	// and gets sync as the default, letting --mode override it.
610	func defaultOperationMode(defaultMode gitsync.OperationMode) operationMode {
611		if defaultMode != "" {
612			return operationMode(defaultMode)
613		}
614		return operationMode(gitsync.ModeSync)
615	}
