345	func makeCommits(t *testing.T, repo *git.Repository, fs billy.Filesystem, count int) {
346		t.Helper()
347	
348		wt, err := repo.Worktree()
349		if err != nil {
350			t.Fatalf("open worktree: %v", err)
351		}
352	
353		for i := range count {
354			content := strings.Repeat(fmt.Sprintf("line %d %d\n", i, time.Now().UnixNano()), 24)
355			file, err := fs.Create("tracked.txt")
356			if err != nil {
357				t.Fatalf("create file: %v", err)
358			}
359			if _, err := io.WriteString(file, content); err != nil {
360				t.Fatalf("write file: %v", err)
361			}
362			if err := file.Close(); err != nil {
363				t.Fatalf("close file: %v", err)
364			}
365	
366			if _, err := wt.Add("tracked.txt"); err != nil {
367				t.Fatalf("add file: %v", err)
368			}
369	
370			_, err = wt.Commit(fmt.Sprintf("commit %d", i), &git.CommitOptions{
371				Author:    &objectSignature,
372				Committer: &objectSignature,
373			})
374			if err != nil {
375				t.Fatalf("commit: %v", err)
376			}
377		}
378	}
