431	func (s *smartHTTPRepoServer) handle(w http.ResponseWriter, r *http.Request) {
432		switch {
433		case r.Method == http.MethodGet && r.URL.Path == s.repoPath+"/info/refs":
434			s.handleInfoRefs(w, r)
435		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-upload-pack":
436			s.handleUploadPack(w, r)
437		case r.Method == http.MethodPost && r.URL.Path == s.repoPath+"/git-receive-pack":
438			s.handleReceivePack(w, r)
439		default:
440			http.NotFound(w, r)
441		}
442	}
443	
444	func (s *smartHTTPRepoServer) handleInfoRefs(w http.ResponseWriter, r *http.Request) {
445		service := r.URL.Query().Get("service")
446		if service != transport.UploadPackService && service != transport.ReceivePackService {
447			http.Error(w, "missing service", http.StatusBadRequest)
448			return
449		}
450	
451		var buf bytes.Buffer
452		if err := transport.AdvertiseRefs(r.Context(), s.repo.Storer, &buf, service, false); err != nil {
453			http.Error(w, err.Error(), http.StatusInternalServerError)
454			return
455		}
456		if service == transport.ReceivePackService && s.thinCapable {
457			rewritten, err := rewriteReceivePackAdvertisement(buf.Bytes(), func(caps *capability.List) {
458				caps.Delete(capability.Capability("no-thin"))
459			})
460			if err != nil {
461				s.t.Fatalf("rewrite receive-pack advertisement: %v", err)
462			}
463			buf.Reset()
464			_, _ = buf.Write(rewritten)
465		}
466	
467		w.Header().Set("Content-Type", fmt.Sprintf("application/x-%s-advertisement", service))
468		if _, err := w.Write(buf.Bytes()); err != nil {
469			s.t.Fatalf("write advertised refs: %v", err)
470		}
471	}
472	
473	func rewriteReceivePackAdvertisement(data []byte, mutate func(*capability.List)) ([]byte, error) {
474		ar := packp.NewAdvRefs()
475		if err := ar.Decode(bytes.NewReader(data)); err == nil {
476			mutate(ar.Capabilities)
477			var buf bytes.Buffer
478			if err := ar.Encode(&buf); err != nil {
479				return nil, err
480			}
481			return buf.Bytes(), nil
482		}
483	
484		rd := bytes.NewReader(data)
485		var smart packp.SmartReply
486		if err := smart.Decode(rd); err != nil {
487			return nil, err
488		}
489		ar = packp.NewAdvRefs()
490		if err := ar.Decode(rd); err != nil {
491			return nil, err
492		}
493		mutate(ar.Capabilities)
494		var buf bytes.Buffer
495		if err := smart.Encode(&buf); err != nil {
496			return nil, err
497		}
498		if err := ar.Encode(&buf); err != nil {
499			return nil, err
500		}
501		return buf.Bytes(), nil
502	}
503	
504	func (s *smartHTTPRepoServer) handleUploadPack(w http.ResponseWriter, r *http.Request) {
505		var buf bytes.Buffer
506		wc := nopWriteCloser{&buf}
507	
508		err := transport.UploadPack(r.Context(), s.repo.Storer, r.Body, wc, &transport.UploadPackRequest{
509			StatelessRPC: true,
510		})
511		if err != nil {
512			http.Error(w, err.Error(), http.StatusInternalServerError)
513			return
514		}
515	
516		w.Header().Set("Content-Type", "application/x-git-upload-pack-result")
517		if _, err := w.Write(buf.Bytes()); err != nil {
518			s.t.Fatalf("write upload-pack response: %v", err)
519		}
520	}
521	
522	func (s *smartHTTPRepoServer) handleReceivePack(w http.ResponseWriter, r *http.Request) {
523		s.mu.Lock()
524		s.receivePacks++
525		s.mu.Unlock()
526	
527		var buf bytes.Buffer
528		wc := nopWriteCloser{&buf}
529	
530		err := transport.ReceivePack(r.Context(), s.repo.Storer, r.Body, wc, &transport.ReceivePackRequest{
531			StatelessRPC: true,
532		})
533	
534		w.Header().Set("Content-Type", "application/x-git-receive-pack-result")
535		if buf.Len() > 0 {
536			if _, err := w.Write(buf.Bytes()); err != nil {
537				s.t.Fatalf("write receive-pack response: %v", err)
538			}
539		}
540		if err != nil {
541			return
542		}
543	}
544	
545	// nopWriteCloser wraps an io.Writer to satisfy io.WriteCloser.
546	type nopWriteCloser struct{ io.Writer }
547	
548	func (nopWriteCloser) Close() error { return nil }
